# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public int damage = 10;

    public void TakeDamage(int amount)
    {
        health -= amount;
        if (health < 0)
            health = 0;
    }

    public void Heal(int amount)
    {
        health += amount;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int price)
    {
        if (currency >= price)
        {
            currency -= price;
            return true;
        }
        return false;
    }
}

public class Shop : MonoBehaviour
{
    public int healthPotionPrice = 50;
    public int damageUpgradePrice = 100;

    public void BuyHealthPotion(Player player)
    {
        if (player.PurchaseItem(healthPotionPrice))
        {
            player.Heal(20);
        }
    }

    public void BuyDamageUpgrade(Player player)
    {
        if (player.PurchaseItem(damageUpgradePrice))
        {
            player.damage += 5;
        }
    }
}

public class GameManager : MonoBehaviour
{
    public Player player;
    public Shop shop;

    void Start()
    {
        player = new Player();
        shop = new Shop();
    }

    void Update()
    {
        // Example usage
        if (Input.GetKeyDown(KeyCode.H))
        {
            shop.BuyHealthPotion(player);
        }

        if (Input.GetKeyDown(KeyCode.D))
        {
            shop.BuyDamageUpgrade(player);
        }
    }
}